#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define WIDTH 16
#define HEIGHT 16
#define ETA 0.3f
#define MOMENTUM 0.3f

__kernel void
bpnn_layerforward_CUDA(__global float *input_cuda,
                       __global float *output_hidden_cuda,
                       __global float *input_hidden_cuda,
                       __global float *hidden_partial_sum,
                       const int in,
                       const int hid) 
{
   int by = get_group_id(1);
   int tx = get_local_id(0);
   int ty = get_local_id(1);

   int index =  ( hid + 1 ) * HEIGHT * by + ( hid + 1 ) * ty + tx + 1 + ( hid + 1 ) ;  

   int index_in = HEIGHT * by + ty + 1;

   __local float input_node[HEIGHT];
   __local float weight_matrix[HEIGHT][WIDTH];

   if ( tx == 0 )
       input_node[ty] = input_cuda[index_in];

   barrier(CLK_LOCAL_MEM_FENCE);

   weight_matrix[ty][tx] = input_hidden_cuda[index];

   barrier(CLK_LOCAL_MEM_FENCE);

   weight_matrix[ty][tx] = weight_matrix[ty][tx] * input_node[ty];

   barrier(CLK_LOCAL_MEM_FENCE);

   int log_height = 0;
   for (int temp = HEIGHT; temp > 1; temp >>=1) {
       log_height++;
   }

   for ( int i = 1 ; i <= log_height ; i++){
       int power_two = 1 << i;

       if( (ty % power_two) == 0 )
           weight_matrix[ty][tx] = weight_matrix[ty][tx] + weight_matrix[ty + power_two/2][tx];

       barrier(CLK_LOCAL_MEM_FENCE);
   }

   input_hidden_cuda[index] = weight_matrix[ty][tx];

   barrier(CLK_LOCAL_MEM_FENCE);

   if ( tx == 0 ) {
       hidden_partial_sum[by * hid + ty] = weight_matrix[tx][ty];
   }
}


__kernel void bpnn_adjust_weights_cuda(__global float * delta,   
                                      const int hid,         
                                      __global float * ly,      
                                      const int in,          
                                      __global float * w,       
                                      __global float * oldw)  									
{
   int by = get_group_id(1);

   int tx = get_local_id(0);
   int ty = get_local_id(1);

   int index =  ( hid + 1 ) * HEIGHT * by + ( hid + 1 ) * ty + tx + 1 + ( hid + 1 ) ;  
   int index_y = HEIGHT * by + ty + 1;
   int index_x = tx + 1;

   float new_dw = ((ETA * delta[index_x] * ly[index_y]) + (MOMENTUM * oldw[index]));
   w[index] += new_dw;
   oldw[index] = new_dw;

   barrier(CLK_LOCAL_MEM_FENCE);

   if (ty == 0 && by == 0){
       float new_dw_bias = ((ETA * delta[index_x]) + (MOMENTUM * oldw[index_x]));
       w[index_x] += new_dw_bias;
       oldw[index_x] = new_dw_bias;
   }
}
